import {
  MARKER_HALF_WIDTH,
  SQUARE_HEIGHT,
  TRIANGLE_HEIGHT,
} from '../constants.js';

export const calculateLeftMarkerVertexes = (
  x: number,
  y: number,
  width: number,
) => {
  const leftXValues = x;
  const rightXValues = x + width;
  const bottomYValues = y + SQUARE_HEIGHT;

  const bottomLeftVertex = { x, y: bottomYValues + TRIANGLE_HEIGHT };
  const topLeftVertex = { x: leftXValues, y };
  const topRightVertex = { x: rightXValues, y };
  const bottomRightVertex = { x: rightXValues, y: bottomYValues };
  const triangleBottomRightJoint = {
    x: x + MARKER_HALF_WIDTH,
    y: bottomYValues,
  };

  return [
    bottomLeftVertex,
    topLeftVertex,
    topRightVertex,
    bottomRightVertex,
    triangleBottomRightJoint,
  ];
};
